import{_ as a,o as l,c as r,a2 as i}from"./chunks/framework.CGYl2SZ_.js";const t=JSON.parse('{"title":"OpenClaw 咨询与部署服务","description":"专业 OpenClaw 部署、培训、定制开发服务。1 对 1 咨询 ¥299 起，企业部署 ¥999 起。","frontmatter":{"title":"OpenClaw 咨询与部署服务","description":"专业 OpenClaw 部署、培训、定制开发服务。1 对 1 咨询 ¥299 起，企业部署 ¥999 起。"},"headers":[],"relativePath":"services.md","filePath":"services.md"}');const o=a({name:"services.md"},[["render",function(a,t,o,e,n,s){return l(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="🛠-openclaw-咨询与部署服务" tabindex="-1">🛠 OpenClaw 咨询与部署服务 <a class="header-anchor" href="#🛠-openclaw-咨询与部署服务" aria-label="Permalink to &quot;🛠 OpenClaw 咨询与部署服务&quot;">​</a></h1><p><strong>专业 · 高效 · 可落地</strong></p><hr><h2 id="💡-我能帮你什么" tabindex="-1">💡 我能帮你什么？ <a class="header-anchor" href="#💡-我能帮你什么" aria-label="Permalink to &quot;💡 我能帮你什么？&quot;">​</a></h2><p>OpenClaw 功能强大，但配置复杂。我帮你：</p><ul><li>✅ <strong>快速部署</strong> - 3 小时完成从零到上线</li><li>✅ <strong>问题解答</strong> - 1 对 1 解决你的具体问题</li><li>✅ <strong>团队培训</strong> - 让你的团队快速上手</li><li>✅ <strong>定制开发</strong> - 根据你的需求定制 Agent 和工作流</li></ul><p><strong>不卖课程，只给结果。</strong></p><hr><h2 id="📋-服务类型" tabindex="-1">📋 服务类型 <a class="header-anchor" href="#📋-服务类型" aria-label="Permalink to &quot;📋 服务类型&quot;">​</a></h2><h3 id="_1️⃣-快速咨询-¥299-次" tabindex="-1">1️⃣ 快速咨询 - ¥299/次 <a class="header-anchor" href="#_1️⃣-快速咨询-¥299-次" aria-label="Permalink to &quot;1️⃣ 快速咨询 - ¥299/次&quot;">​</a></h3><p><strong>适合</strong>: 有具体问题需要解答</p><p><strong>包含</strong>:</p><ul><li>30 分钟 1 对 1 视频/语音咨询</li><li>解答 OpenClaw 使用问题</li><li>配置建议和优化方案</li><li>会后总结文档</li></ul><p><strong>预约</strong>: <a href="#预约方式">立即预约</a></p><hr><h3 id="_2️⃣-部署指导-¥999-次-⭐-推荐" tabindex="-1">2️⃣ 部署指导 - ¥999/次 ⭐ 推荐 <a class="header-anchor" href="#_2️⃣-部署指导-¥999-次-⭐-推荐" aria-label="Permalink to &quot;2️⃣ 部署指导 - ¥999/次 ⭐ 推荐&quot;">​</a></h3><p><strong>适合</strong>: 想自己部署但需要指导</p><p><strong>包含</strong>:</p><ul><li>2-3 小时远程指导</li><li>从零到上线完整部署</li><li>配置 3-5 个常用渠道</li><li>配置 2-3 个 Agent</li><li>7 天售后支持</li></ul><p><strong>交付</strong>:</p><ul><li>✅ 可运行的 OpenClaw 系统</li><li>✅ 配置文档</li><li>✅ 使用指南</li></ul><p><strong>预约</strong>: <a href="#预约方式">立即预约</a></p><hr><h3 id="_3️⃣-企业培训-¥4-999-次" tabindex="-1">3️⃣ 企业培训 - ¥4,999/次 <a class="header-anchor" href="#_3️⃣-企业培训-¥4-999-次" aria-label="Permalink to &quot;3️⃣ 企业培训 - ¥4,999/次&quot;">​</a></h3><p><strong>适合</strong>: 团队需要系统学习 OpenClaw</p><p><strong>包含</strong>:</p><ul><li>1 天集中培训（6 小时）</li><li>最多 10 人参加</li><li>理论 + 实战结合</li><li>培训材料 + 录屏</li><li>30 天售后支持</li></ul><p><strong>大纲</strong>:</p><ul><li>上午：OpenClaw 基础 + 部署</li><li>下午：实战演练 + 问题解答</li></ul><p><strong>预约</strong>: <a href="#预约方式">联系定制方案</a></p><hr><h3 id="_4️⃣-定制开发-¥10-000-起" tabindex="-1">4️⃣ 定制开发 - ¥10,000 起 <a class="header-anchor" href="#_4️⃣-定制开发-¥10-000-起" aria-label="Permalink to &quot;4️⃣ 定制开发 - ¥10,000 起&quot;">​</a></h3><p><strong>适合</strong>: 有特殊需求需要定制</p><p><strong>包含</strong>:</p><ul><li>需求分析和方案评估</li><li>定制 Agent 开发</li><li>定制工作流开发</li><li>第三方系统集成</li><li>交付源码和文档</li></ul><p><strong>案例</strong>:</p><ul><li>客服机器人定制</li><li>自动化工作流</li><li>多 Agent 协作系统</li></ul><p><strong>预约</strong>: <a href="#预约方式">联系评估</a></p><hr><h3 id="_5️⃣-月度顾问-¥3-000-月" tabindex="-1">5️⃣ 月度顾问 - ¥3,000/月 <a class="header-anchor" href="#_5️⃣-月度顾问-¥3-000-月" aria-label="Permalink to &quot;5️⃣ 月度顾问 - ¥3,000/月&quot;">​</a></h3><p><strong>适合</strong>: 需要长期技术支持</p><p><strong>包含</strong>:</p><ul><li>每月 4 次咨询（每周 1 次）</li><li>紧急问题优先响应</li><li>系统优化建议</li><li>新功能配置指导</li></ul><p><strong>预约</strong>: <a href="#预约方式">立即预约</a></p><hr><h2 id="🎯-为什么选择我" tabindex="-1">🎯 为什么选择我？ <a class="header-anchor" href="#🎯-为什么选择我" aria-label="Permalink to &quot;🎯 为什么选择我？&quot;">​</a></h2><h3 id="实战经验" tabindex="-1">实战经验 <a class="header-anchor" href="#实战经验" aria-label="Permalink to &quot;实战经验&quot;">​</a></h3><ul><li>✅ OP 鸭项目从 0 到 1 搭建</li><li>✅ 61+ 页面，228,000 字教程</li><li>✅ 多 Agent 架构实战经验</li></ul><h3 id="技术能力" tabindex="-1">技术能力 <a class="header-anchor" href="#技术能力" aria-label="Permalink to &quot;技术能力&quot;">​</a></h3><ul><li>✅ OpenClaw 深度用户</li><li>✅ 熟悉所有核心功能</li><li>✅ 多渠道配置经验</li></ul><h3 id="服务意识" tabindex="-1">服务意识 <a class="header-anchor" href="#服务意识" aria-label="Permalink to &quot;服务意识&quot;">​</a></h3><ul><li>✅ 结果导向，不卖焦虑</li><li>✅ 快速响应，解决问题</li><li>✅ 售后支持，负责到底</li></ul><hr><h2 id="📝-服务流程" tabindex="-1">📝 服务流程 <a class="header-anchor" href="#📝-服务流程" aria-label="Permalink to &quot;📝 服务流程&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 预约 → 2. 沟通需求 → 3. 确认方案 → 4. 支付定金 → 5. 执行服务 → 6. 交付验收 → 7. 支付尾款 → 8. 售后支持</span></span></code></pre></div><h3 id="详细说明" tabindex="-1">详细说明 <a class="header-anchor" href="#详细说明" aria-label="Permalink to &quot;详细说明&quot;">​</a></h3><p><strong>1. 预约</strong></p><ul><li>填写预约表单或添加微信</li><li>说明你的需求和期望时间</li></ul><p><strong>2. 沟通需求</strong></p><ul><li>15-30 分钟免费沟通</li><li>了解你的具体情况</li><li>推荐合适的服务</li></ul><p><strong>3. 确认方案</strong></p><ul><li>提供服务方案</li><li>确认时间和交付物</li><li>发送服务协议</li></ul><p><strong>4. 支付定金</strong></p><ul><li>支付 50% 定金</li><li>支付宝/微信/银行转账</li><li>发送付款凭证</li></ul><p><strong>5. 执行服务</strong></p><ul><li>按约定时间执行</li><li>过程中保持沟通</li><li>及时调整方案</li></ul><p><strong>6. 交付验收</strong></p><ul><li>交付所有成果</li><li>确认验收</li><li>收集反馈</li></ul><p><strong>7. 支付尾款</strong></p><ul><li>验收后支付尾款</li><li>发送付款凭证</li></ul><p><strong>8. 售后支持</strong></p><ul><li>按服务类型提供支持</li><li>解答后续问题</li></ul><hr><h2 id="💰-付款方式" tabindex="-1">💰 付款方式 <a class="header-anchor" href="#💰-付款方式" aria-label="Permalink to &quot;💰 付款方式&quot;">​</a></h2><p><strong>支持</strong>:</p><ul><li>支付宝</li><li>微信支付</li><li>银行转账（企业客户）</li></ul><p><strong>定金</strong>: 50% 预付款，确认后开始服务<br><strong>尾款</strong>: 交付验收后支付</p><p><strong>退款政策</strong>:</p><ul><li>服务开始前可全额退款</li><li>服务开始后可按比例退款</li><li>因我方原因无法完成，全额退款</li></ul><hr><h2 id="❓-常见问题" tabindex="-1">❓ 常见问题 <a class="header-anchor" href="#❓-常见问题" aria-label="Permalink to &quot;❓ 常见问题&quot;">​</a></h2><h3 id="q1-服务是远程还是现场" tabindex="-1">Q1: 服务是远程还是现场？ <a class="header-anchor" href="#q1-服务是远程还是现场" aria-label="Permalink to &quot;Q1: 服务是远程还是现场？&quot;">​</a></h3><p><strong>A</strong>: 默认远程（视频会议 + 屏幕共享），北京地区可协商现场服务（额外收费）。</p><h3 id="q2-如果我的问题很简单-值得咨询吗" tabindex="-1">Q2: 如果我的问题很简单，值得咨询吗？ <a class="header-anchor" href="#q2-如果我的问题很简单-值得咨询吗" aria-label="Permalink to &quot;Q2: 如果我的问题很简单，值得咨询吗？&quot;">​</a></h3><p><strong>A</strong>: 值得！30 分钟可能解决你几天的问题。而且我会帮你排查潜在问题。</p><h3 id="q3-部署指导后我还是不会用怎么办" tabindex="-1">Q3: 部署指导后我还是不会用怎么办？ <a class="header-anchor" href="#q3-部署指导后我还是不会用怎么办" aria-label="Permalink to &quot;Q3: 部署指导后我还是不会用怎么办？&quot;">​</a></h3><p><strong>A</strong>: 包含 7 天售后支持，有问题随时问。如果还是不会，免费再指导一次。</p><h3 id="q4-企业培训可以定制内容吗" tabindex="-1">Q4: 企业培训可以定制内容吗？ <a class="header-anchor" href="#q4-企业培训可以定制内容吗" aria-label="Permalink to &quot;Q4: 企业培训可以定制内容吗？&quot;">​</a></h3><p><strong>A</strong>: 可以！会根据你的团队情况定制培训内容和案例。</p><h3 id="q5-定制开发如何报价" tabindex="-1">Q5: 定制开发如何报价？ <a class="header-anchor" href="#q5-定制开发如何报价" aria-label="Permalink to &quot;Q5: 定制开发如何报价？&quot;">​</a></h3><p><strong>A</strong>: 根据需求复杂度评估，简单功能 ¥10,000 起，复杂系统面议。</p><h3 id="q6-可以开发票吗" tabindex="-1">Q6: 可以开发票吗？ <a class="header-anchor" href="#q6-可以开发票吗" aria-label="Permalink to &quot;Q6: 可以开发票吗？&quot;">​</a></h3><p><strong>A</strong>: 企业客户可开发票（需加税点），个人客户暂不提供。</p><hr><h2 id="📞-预约方式" tabindex="-1">📞 预约方式 <a class="header-anchor" href="#📞-预约方式" aria-label="Permalink to &quot;📞 预约方式&quot;">​</a></h2><h3 id="方式-1-微信-推荐-⭐" tabindex="-1">方式 1: 微信（推荐）⭐ <a class="header-anchor" href="#方式-1-微信-推荐-⭐" aria-label="Permalink to &quot;方式 1: 微信（推荐）⭐&quot;">​</a></h3><p>添加微信：<strong><code>Q_1526223</code></strong> 备注：&quot;OpenClaw 咨询&quot; 响应时间：通常 1 小时内回复</p><h3 id="方式-2-飞书" tabindex="-1">方式 2: 飞书 <a class="header-anchor" href="#方式-2-飞书" aria-label="Permalink to &quot;方式 2: 飞书&quot;">​</a></h3><p>直接在飞书中联系我（当前会话） 响应时间：工作时间即时回复</p><h3 id="方式-3-邮箱" tabindex="-1">方式 3: 邮箱 <a class="header-anchor" href="#方式-3-邮箱" aria-label="Permalink to &quot;方式 3: 邮箱&quot;">​</a></h3><p>发送邮件至：<strong><code>1526223@qq.com</code></strong> 主题：OpenClaw 咨询服务 - [你的名字] 响应时间：24 小时内回复</p><h3 id="方式-4-预约表单" tabindex="-1">方式 4: 预约表单 <a class="header-anchor" href="#方式-4-预约表单" aria-label="Permalink to &quot;方式 4: 预约表单&quot;">​</a></h3><p>即将上线，敬请期待</p><hr><p><strong>工作时间</strong>: 周一至周日 08:00-22:00<br><strong>响应承诺</strong>: 工作时间内 1 小时回复，非工作时间 24 小时回复</p><hr><h2 id="🎁-限时优惠" tabindex="-1">🎁 限时优惠 <a class="header-anchor" href="#🎁-限时优惠" aria-label="Permalink to &quot;🎁 限时优惠&quot;">​</a></h2><p><strong>开业优惠</strong>（前 10 名客户）:</p><ul><li>快速咨询：<s>¥299</s> → <strong>¥199</strong></li><li>部署指导：<s>¥999</s> → <strong>¥799</strong></li><li>企业培训：<s>¥4,999</s> → <strong>¥3,999</strong></li></ul><p><strong>推荐奖励</strong>:</p><ul><li>推荐客户成交，双方各得 ¥200 优惠券</li></ul><hr><h2 id="📊-客户评价" tabindex="-1">📊 客户评价 <a class="header-anchor" href="#📊-客户评价" aria-label="Permalink to &quot;📊 客户评价&quot;">​</a></h2><p><em>（此处展示客户评价，服务后补充）</em></p><hr><h2 id="🚀-立即开始" tabindex="-1">🚀 立即开始 <a class="header-anchor" href="#🚀-立即开始" aria-label="Permalink to &quot;🚀 立即开始&quot;">​</a></h2><p><strong>别犹豫，现在就预约！</strong></p><p>时间是最昂贵的成本，早一天部署，早一天受益。</p><p><a href="#预约方式">立即预约</a> | <a href="#预约方式">联系咨询</a> | <a href="/tutorials/">查看教程</a></p><hr><p><strong>最后更新</strong>: 2026-03-31<br><strong>服务状态</strong>: 🟢 接受预约</p>',121)])])}]]);export{t as __pageData,o as default};
